/**
 * Dashboard Component
 * Display statistics and overview
 */

import React from 'react';
import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Building2, Zap, TrendingUp, DollarSign } from 'lucide-react';

const Dashboard = ({ stats, buildings }) => {
  // Calculate statistics
  const totalBuildings = buildings.length;
  const avgConfidence = buildings.length > 0 
    ? (buildings.reduce((sum, b) => sum + b.confidence, 0) / buildings.length * 100).toFixed(1)
    : 0;
  const totalArea = buildings.reduce((sum, b) => sum + b.area_m2, 0);
  const estimatedSolarPotential = (totalArea * 0.5 * 0.2 * 5.06 * 365 * 0.8 / 1000).toFixed(0); // MWh/year

  // Confidence distribution
  const confidenceData = [
    { name: '≥90%', value: buildings.filter(b => b.confidence >= 0.9).length, color: '#10b981' },
    { name: '80-90%', value: buildings.filter(b => b.confidence >= 0.8 && b.confidence < 0.9).length, color: '#3b82f6' },
    { name: '70-80%', value: buildings.filter(b => b.confidence >= 0.7 && b.confidence < 0.8).length, color: '#f59e0b' },
    { name: '<70%', value: buildings.filter(b => b.confidence < 0.7).length, color: '#ef4444' },
  ];

  // Area distribution
  const areaData = [
    { name: '<100 m²', count: buildings.filter(b => b.area_m2 < 100).length },
    { name: '100-500 m²', count: buildings.filter(b => b.area_m2 >= 100 && b.area_m2 < 500).length },
    { name: '500-1000 m²', count: buildings.filter(b => b.area_m2 >= 500 && b.area_m2 < 1000).length },
    { name: '1000-5000 m²', count: buildings.filter(b => b.area_m2 >= 1000 && b.area_m2 < 5000).length },
    { name: '>5000 m²', count: buildings.filter(b => b.area_m2 >= 5000).length },
  ];

  return (
    <div style={{
      position: 'absolute',
      top: '16px',
      left: '16px',
      backgroundColor: 'white',
      borderRadius: '12px',
      boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
      zIndex: 1000,
      maxWidth: '400px',
      maxHeight: 'calc(100vh - 32px)',
      overflow: 'auto'
    }}>
      {/* Header */}
      <div style={{
        padding: '20px',
        borderBottom: '1px solid #e5e7eb'
      }}>
        <h2 style={{ fontSize: '20px', fontWeight: 'bold', marginBottom: '4px' }}>
          Solar Potential Dashboard
        </h2>
        <p style={{ fontSize: '14px', color: '#6b7280' }}>
          ภาพรวมข้อมูลอาคารและศักยภาพโซลาร์เซลล์
        </p>
      </div>

      {/* Stats Cards */}
      <div style={{ padding: '20px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '20px' }}>
          <StatCard
            icon={<Building2 size={20} />}
            label="อาคารทั้งหมด"
            value={totalBuildings.toLocaleString()}
            color="#3b82f6"
          />
          <StatCard
            icon={<TrendingUp size={20} />}
            label="ความแม่นยำเฉลี่ย"
            value={`${avgConfidence}%`}
            color="#10b981"
          />
          <StatCard
            icon={<Zap size={20} />}
            label="ศักยภาพโซลาร์"
            value={`${estimatedSolarPotential} MWh/ปี`}
            color="#f59e0b"
          />
          <StatCard
            icon={<DollarSign size={20} />}
            label="มูลค่าประหยัด"
            value={`฿${(estimatedSolarPotential * 4.18).toFixed(0)}M/ปี`}
            color="#8b5cf6"
          />
        </div>

        {/* Confidence Distribution */}
        <div style={{ marginBottom: '20px' }}>
          <h3 style={{ fontSize: '14px', fontWeight: '600', marginBottom: '12px' }}>
            การกระจายความแม่นยำ
          </h3>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie
                data={confidenceData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                outerRadius={60}
                fill="#8884d8"
                dataKey="value"
              >
                {confidenceData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Area Distribution */}
        <div>
          <h3 style={{ fontSize: '14px', fontWeight: '600', marginBottom: '12px' }}>
            การกระจายขนาดพื้นที่
          </h3>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={areaData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" style={{ fontSize: '10px' }} />
              <YAxis />
              <Tooltip />
              <Bar dataKey="count" fill="#3b82f6" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Summary */}
        <div style={{
          marginTop: '20px',
          padding: '12px',
          backgroundColor: '#f3f4f6',
          borderRadius: '8px',
          fontSize: '12px',
          color: '#4b5563'
        }}>
          <p style={{ marginBottom: '4px' }}>
            <strong>พื้นที่รวม:</strong> {(totalArea / 1000000).toFixed(2)} km²
          </p>
          <p style={{ marginBottom: '4px' }}>
            <strong>พื้นที่เฉลี่ย:</strong> {totalBuildings > 0 ? (totalArea / totalBuildings).toFixed(1) : 0} m²
          </p>
          <p>
            <strong>ข้อมูลจาก:</strong> Google Open Buildings Dataset
          </p>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ icon, label, value, color }) => (
  <div style={{
    padding: '12px',
    backgroundColor: '#f9fafb',
    borderRadius: '8px',
    border: '1px solid #e5e7eb'
  }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
      <div style={{ color }}>{icon}</div>
      <span style={{ fontSize: '12px', color: '#6b7280' }}>{label}</span>
    </div>
    <div style={{ fontSize: '18px', fontWeight: 'bold', color: '#111827' }}>
      {value}
    </div>
  </div>
);

export default Dashboard;
